const c = $('Execute Workflow Trigger').first().json;
const today = new Date().toISOString().slice(0, 10);

function safeList(nodeName) {
  try {
    const d = $(nodeName).first().json;
    return Array.isArray(d.list) ? d.list : [];
  } catch(e) { return []; }
}

const packages    = safeList('HTTP · Get Packages');
const umrahGroups = safeList('HTTP · Get Umrah Groups').filter(g => g.departure_date >= today);
const cars        = safeList('HTTP · Get Cars');
const itineraries = safeList('HTTP · Get Itineraries');

let block = '';

if (packages.length) {
  const lines = packages.map(p => {
    let l = `- ${p.name}`;
    if (p.destination) l += ` | Destination: ${p.destination}`;
    if (p.nights)      l += ` | ${p.nights} nights`;
    if (p.type)        l += ` | Type: ${p.type}`;
    if (p.sell_price || p.base_price) l += ` | Price: ${p.currency||'INR'} ${p.sell_price||p.base_price}/person`;
    if (p.pax_min || p.pax_max) l += ` | Pax: ${p.pax_min||1}-${p.pax_max||''}`;
    try { const inc = JSON.parse(p.inclusions||'[]'); if (inc.length) l += ` | Includes: ${inc.join(', ')}`; } catch(e) {}
    return l;
  }).join('\n');
  block += '\n\n## Travel Packages\n' + lines;
}

if (umrahGroups.length) {
  const lines = umrahGroups.map(g => `- ${g.name} | Departs: ${g.departure_date} | Seats: ${g.seats||0} | ${g.currency||'INR'} ${g.price_per_pax||''}/person`).join('\n');
  block += '\n\n## Upcoming Umrah / Hajj Groups\n' + lines;
}

if (itineraries.length) {
  const lines = itineraries.map(it => {
    let days = []; try { days = JSON.parse(it.days||'[]'); } catch(e) {}
    return `- ${it.title||it.name}${it.destination?' | '+it.destination:''} | ${days.length} days`;
  }).join('\n');
  block += '\n\n## Itineraries\n' + lines;
}

if (cars.length) {
  const lines = cars.map(car => `- ${car.name}${car.category?' ('+car.category+')':''} | ${car.seats||'?'} seats | ${car.currency||'INR'} ${car.daily_rate||0}/day${car.plate_no?' | Plate: '+car.plate_no:''}`).join('\n');
  block += '\n\n## Available Cars for Rent\n' + lines;
}

return [{ json: { ...c, taContextBlock: block } }];
